import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { format } from 'date-fns';

export const useStore = create(
  persist(
    (set, get) => ({
      members: [
        { id: '1', name: 'আব্দুল রহিম', avatar: 'https://i.pravatar.cc/150?u=rahim' },
        { id: '2', name: 'করিম উদ্দিন', avatar: 'https://i.pravatar.cc/150?u=karim' },
        { id: '3', name: 'ফাতেমা বেগম', avatar: 'https://i.pravatar.cc/150?u=fatema' },
        { id: '4', name: 'সোহেল রানা', avatar: 'https://i.pravatar.cc/150?u=sohel' },
      ],
      transactions: [
        { id: 't1', date: '2025-03-10', type: 'deposit', amount: 5000, memberId: '1', description: 'মাসিক চাঁদা' },
        { id: 't2', date: '2025-03-11', type: 'deposit', amount: 3000, memberId: '2', description: 'মাসিক চাঁদা' },
        { id: 't3', date: '2025-03-12', type: 'expense', amount: 2000, description: 'স্কুল ফি' },
        { id: 't4', date: '2025-03-13', type: 'donation', amount: 1500, description: 'রাহিম ভাইকে (অসুস্থ)' },
      ],

      addMember: (name, avatar) =>
        set((state) => ({
          members: [...state.members, { id: Date.now().toString(), name, avatar }],
        })),

      deleteMember: (id) =>
        set((state) => ({
          members: state.members.filter((m) => m.id !== id),
          transactions: state.transactions.filter((t) => t.memberId !== id),
        })),

      addTransaction: (newTx) =>
        set((state) => ({
          transactions: [
            ...state.transactions,
            { ...newTx, id: Date.now().toString(), date: new Date().toISOString().split('T')[0] },
          ],
        })),

      deleteTransaction: (id) =>
        set((state) => ({
          transactions: state.transactions.filter((t) => t.id !== id),
        })),

      get totalBalance() {
        const state = get();
        const dep = state.transactions
          .filter((t) => t.type === 'deposit')
          .reduce((sum, t) => sum + t.amount, 0);
        const exp = state.transactions
          .filter((t) => t.type === 'expense')
          .reduce((sum, t) => sum + t.amount, 0);
        const don = state.transactions
          .filter((t) => t.type === 'donation')
          .reduce((sum, t) => sum + t.amount, 0);
        return dep - exp - don;
      },

      get totalDeposit() {
        return get().transactions
          .filter((t) => t.type === 'deposit')
          .reduce((sum, t) => sum + t.amount, 0);
      },

      get totalExpense() {
        return get().transactions
          .filter((t) => t.type === 'expense')
          .reduce((sum, t) => sum + t.amount, 0);
      },

      get totalDonation() {
        return get().transactions
          .filter((t) => t.type === 'donation')
          .reduce((sum, t) => sum + t.amount, 0);
      },

      getMemberContributed: (memberId) =>
        get().transactions
          .filter((t) => t.type === 'deposit' && t.memberId === memberId)
          .reduce((sum, t) => sum + t.amount, 0),
    }),
    { name: 'group-fund-storage' }
  )
);